class ConfigParserService {

  def parseXmlConfig(xmlString: String): ConfigResponse = {
    if (xmlString == null || xmlString.trim.isEmpty) {
      return ConfigResponse(success = false, config = None, error = Some("XML input is empty or null"))
    }

    // Additional input validation: reject suspiciously large inputs
    if (xmlString.length > 1_000_000) {
      return ConfigResponse(success = false, config = None, error = Some("XML input exceeds maximum allowed size"))
    }

    Try {
      // Use the secure XML loader that disables XXE
      val xml: Elem = SecureXMLLoader.loadString(xmlString)
      extractConfig(xml)
    } match {
      case Success(config) =>
        ConfigResponse(success = true, config = Some(config), error = None)
      case Failure(ex) =>
        val errorMsg = ex match {
          case _: org.xml.sax.SAXParseException =>
            "Invalid XML format or disallowed XML features (DTD/external entities are not permitted)"
          case _: javax.xml.parsers.ParserConfigurationException =>
            "XML parser configuration error"
          case other =>
            s"Failed to parse XML configuration: ${other.getMessage}"
        }
        ConfigResponse(success = false, config = None, error = Some(errorMsg))
    }
  }

  private def extractConfig(root: Elem): ParsedConfig = {
    val settings = mutable.ListBuffer[ConfigSetting]()
    val sections = mutable.ListBuffer[String]()
    val errors = mutable.ListBuffer[String]()

    // Extract sections
    val sectionNodes = root \\ "section"
    for (section <- sectionNodes) {
      val sectionName = (section \ "@name").text.trim
      if (sectionName.nonEmpty) {
        sections += sectionName

        // Extract settings within each section
        val settingNodes = section \ "setting"
        for (setting <- settingNodes) {
          val key = (setting \ "@key").text.trim
          val value = setting.text.trim

          if (key.nonEmpty) {
            settings += ConfigSetting(key = key, value = value, section = sectionName)
          } else {
            errors += s"Setting in section '$sectionName' is missing a 'key' attribute"
          }
        }

        // Also support <property name="..." value="..." /> format
        val propertyNodes = section \ "property"
        for (prop <- propertyNodes) {
          val name = (prop \ "@name").text.trim
          val value = (prop \ "@value").text.trim match {
            case v if v.nonEmpty => v
            case _ => prop.text.trim
          }

          if (name.nonEmpty) {
            settings += ConfigSetting(key = name, value = value, section = sectionName)
          } else {
            errors += s"Property in section '$sectionName' is missing a 'name' attribute"
          }
        }
      } else {
        errors += "Found a <section> element without a 'name' attribute"
      }
    }

    // Also extract top-level settings not in any section
    val topLevelSettings = root \ "setting"
    for (setting <- topLevelSettings) {
      val key = (setting \ "@key").text.trim
      val value = setting.text.trim
      if (key.nonEmpty) {
        settings += ConfigSetting(key = key, value = value, section = "global")
      }
    }

    val topLevelProperties = root \ "property"
    for (prop <- topLevelProperties) {
      val name = (prop \ "@name").text.trim
      val value = (prop \ "@value").text.trim match {
        case v if v.nonEmpty => v
        case _ => prop.text.trim
      }
      if (name.nonEmpty) {
        settings += ConfigSetting(key = name, value = value, section = "global")
      }
    }

    // Extract environment-specific overrides
    val envNodes = root \\ "environment"
    for (env <- envNodes) {
      val envName = (env \ "@name").text.trim
      if (envName.nonEmpty) {
        val envSettings = env \ "setting"
        for (setting <- envSettings) {
          val key = (setting \ "@key").text.trim
          val value = setting.text.trim
          if (key.nonEmpty) {
            settings += ConfigSetting(key = key, value = value, section = s"env:$envName")
          }
        }
      }
    }

    ParsedConfig(
      settings = settings.toList,
      sections = (sections.toList ++ (if (topLevelSettings.nonEmpty || topLevelProperties.nonEmpty) List("global") else Nil)).distinct,
      errors = errors.toList
    )
  }

  def getSettingsBySection(xmlString: String, sectionName: String): ConfigResponse = {
    val fullResponse = parseXmlConfig(xmlString)
    fullResponse match {
      case ConfigResponse(true, Some(config), _) =>
        val filtered = config.settings.filter(_.section == sectionName)
        ConfigResponse(
          success = true,
          config = Some(ParsedConfig(settings = filtered, sections = List(sectionName), errors = config.errors)),
          error = None
        )
      case other => other
    }
  }

  def getSettingByKey(xmlString: String, key: String): Option[ConfigSetting] = {
    val response = parseXmlConfig(xmlString)
    response.config.flatMap(_.settings.find(_.key == key))
  }
}

object ConfigManagementApp extends App {
  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  val configParser = new ConfigParserService()

  val route: Route =
    pathPrefix("api" / "config") {
      concat(
        path("parse") {
          post {
            entity(as[XmlRequest]) { request =>
              val response = configParser.parseXmlConfig(request.xml)
              complete(response)
            }
          }
        },
        path("parse" / "section" / Segment) { sectionName =>
          post {
            entity(as[XmlRequest]) { request =>
              val response = configParser.getSettingsBySection(request.xml, sectionName)
              complete(response)
            }
          }
        },
        path("parse" / "key" / Segment) { key =>
          post {
            entity(as[XmlRequest]) { request =>
              configParser.getSettingByKey(request.xml, key) match {
                case Some(setting) =>
                  complete(ConfigResponse(success = true, config = Some(ParsedConfig(List(setting), List(setting.section), Nil)), error = None))
                case None =>
                  complete(StatusCodes.NotFound -> ConfigResponse(success = false, config = None, error = Some(s"Setting with key '$key' not found")))
              }
            }
          }
        },
        path("health") {
          get {
            complete(StatusCodes.OK -> JsObject("status" -> JsString("healthy")))
          }
        }
      )
    }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      val address = binding.localAddress
      println(s"Configuration Management Service online at http://${address.getHostString}:${address.getPort}/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }
}